   101→export function FocusToolLayout() {
   102→  const { focusMode, focusToolType, focusMaestroId, focusTool, setFocusTool, exitFocusMode } = useUIStore();
   103→  const { studentProfile } = useSettingsStore();
   104→
   105→  const [messages, setMessages] = useState<Message[]>([]);
   106→  const [input, setInput] = useState('');
   107→  const [isLoading, setIsLoading] = useState(false);
   108→  const [isVoiceActive, setIsVoiceActive] = useState(false);
   109→  const [voiceSessionId, _setVoiceSessionId] = useState<string | null>(null);
   110→  const messagesEndRef = useRef<HTMLDivElement>(null);
   111→  const inputRef = useRef<HTMLInputElement>(null);
   112→
   113→  // Determine which maestro/coach to use
   114→  const getMaestroOrCoach = useCallback((): MaestroFull | SupportTeacher | null => {
   115→    // If specific maestro requested
   116→    if (focusMaestroId) {
   117→      const maestro = getMaestroById(focusMaestroId);
   118→      if (maestro) return maestro;
   119→
   120→      // Check if it's a coach
   121→      const coach = getSupportTeacherById(focusMaestroId as 'melissa' | 'roberto' | 'chiara' | 'andrea' | 'favij');
   122→      if (coach) return coach;
   123→    }
   124→
   125→    // Default to coach based on preference or tool type
   126→    const preferredCoach = studentProfile?.preferredCoach || 'melissa';
   127→    const coach = getSupportTeacherById(preferredCoach);
   128→    if (coach) return coach;
   129→
   130→    return null;
   131→  }, [focusMaestroId, studentProfile?.preferredCoach]);
   132→
   133→  const character = getMaestroOrCoach();
   134→
   135→  // Helper to get display properties from either MaestroFull or SupportTeacher
   136→  const getCharacterProps = (char: MaestroFull | SupportTeacher | null) => {
   137→    if (!char) return null;
   138→    // MaestroFull has displayName, SupportTeacher has name
   139→    const isMaestro = 'displayName' in char;
   140→    return {
   141→      name: isMaestro ? (char as MaestroFull).displayName : char.name,
   142→      avatar: char.avatar || '/avatars/default.jpg',
   143→      color: char.color,
   144→      systemPrompt: char.systemPrompt,
   145→      greeting: char.greeting,
   146→    };
   147→  };
   148→
   149→  const characterProps = getCharacterProps(character);
   150→
   151→  // ESC key handler
   152→  useEffect(() => {
   153→    const handleKeyDown = (e: KeyboardEvent) => {
   154→      if (e.key === 'Escape' && focusMode) {
   155→        exitFocusMode();
   156→      }
   157→    };
