   171→      inputRef.current?.focus();
   172→    }
   173→  }, [focusMode]);
   174→
   175→  // Initial greeting message
   176→  useEffect(() => {
   177→    if (focusMode && characterProps && messages.length === 0) {
   178→      const toolNames: Record<ToolType, string> = {
   179→        mindmap: 'mappa mentale',
   180→        quiz: 'quiz',
   181→        flashcard: 'flashcard',
   182→        summary: 'riassunto',
   183→        demo: 'demo interattiva',
   184→        diagram: 'diagramma',
   185→        timeline: 'linea del tempo',
   186→        formula: 'formula',
   187→        chart: 'grafico',
   188→        search: 'ricerca',
   189→        webcam: 'foto',
   190→        pdf: 'PDF',
   191→        homework: 'compiti',
   192→      };
   193→
   194→      const toolName = focusToolType ? toolNames[focusToolType] : 'strumento';
   195→
   196→      setMessages([{
   197→        id: 'greeting',
   198→        role: 'assistant',
   199→        content: `Ciao! Sono ${characterProps.name}. Creiamo insieme una ${toolName}! Di che argomento vuoi parlare?`,
   200→        timestamp: new Date(),
   201→      }]);
   202→    }
   203→  }, [focusMode, characterProps, focusToolType, messages.length]);
   204→
   205→  // Handle sending message
   206→  const handleSend = useCallback(async () => {
   207→    if (!input.trim() || isLoading || !character || !characterProps) return;
   208→
   209→    const userMessage = input.trim();
   210→    setInput('');
   211→    setIsLoading(true);
   212→
   213→    const newUserMessage: Message = {
   214→      id: `user-${Date.now()}`,
   215→      role: 'user',
   216→      content: userMessage,
   217→      timestamp: new Date(),
   218→    };
   219→
   220→    setMessages(prev => [...prev, newUserMessage]);
   221→
   222→    try {
   223→      const response = await fetch('/api/chat', {
   224→        method: 'POST',
   225→        headers: { 'Content-Type': 'application/json' },
   226→        body: JSON.stringify({
   227→          messages: [
   228→            ...messages.map(m => ({ role: m.role, content: m.content })),
   229→            { role: 'user', content: userMessage },
   230→          ],
   231→          systemPrompt: characterProps.systemPrompt,
   232→          maestroId: character.id,
   233→          enableTools: true,
   234→          requestedTool: focusToolType,
   235→        }),
   236→      });
   237→
   238→      if (!response.ok) throw new Error('Failed to send message');
   239→
   240→      const data = await response.json();
   241→
   242→      const assistantMessage: Message = {
   243→        id: `assistant-${Date.now()}`,
   244→        role: 'assistant',
   245→        content: data.content || '',
   246→        timestamp: new Date(),
   247→      };
   248→
   249→      if (data.content) {
   250→        setMessages(prev => [...prev, assistantMessage]);
   251→      }
   252→
   253→      // Handle tool calls if any
   254→      if (data.toolCalls && data.toolCalls.length > 0) {
   255→        const toolCall = data.toolCalls[0];
   256→        const toolType = FUNCTION_NAME_TO_TOOL_TYPE[toolCall.type] || focusToolType || 'mindmap';
   257→        const toolContent = toolCall.result?.data || toolCall.result || toolCall.arguments;
   258→
   259→        setFocusTool({
   260→          id: toolCall.id || `tool-${Date.now()}`,
   261→          type: toolType,
   262→          status: 'completed',
   263→          progress: 1,
   264→          content: toolContent,
   265→          createdAt: new Date(),
   266→        });
   267→      }
   268→    } catch (error) {
   269→      logger.error('Chat error in focus mode', { error });
   270→      setMessages(prev => [...prev, {
   271→        id: `error-${Date.now()}`,
   272→        role: 'assistant',
   273→        content: 'Mi dispiace, c\'è stato un errore. Riprova!',
   274→        timestamp: new Date(),
   275→      }]);
   276→    } finally {
   277→      setIsLoading(false);
   278→    }
   279→  }, [input, isLoading, character, characterProps, messages, focusToolType, setFocusTool]);
   280→
   281→  const handleKeyPress = (e: React.KeyboardEvent) => {
   282→    if (e.key === 'Enter' && !e.shiftKey) {
   283→      e.preventDefault();
   284→      handleSend();
   285→    }
   286→  };
   287→
   288→  if (!focusMode) return null;
   289→
   290→  return (
   291→    <AnimatePresence>
   292→      <motion.div
   293→        initial={{ opacity: 0 }}
   294→        animate={{ opacity: 1 }}
   295→        exit={{ opacity: 0 }}
   296→        className="fixed inset-0 z-50 bg-white dark:bg-slate-950"
   297→      >
   298→        {/* Header */}
   299→        <header className="h-14 flex items-center justify-between px-4 border-b border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900">
   300→          <div className="flex items-center gap-3">
   301→            {characterProps && (
   302→              <>
   303→                <div
   304→                  className="w-8 h-8 rounded-full bg-cover bg-center"
   305→                  style={{ backgroundImage: `url(${characterProps.avatar})` }}
   306→                />
   307→                <span className="font-semibold text-slate-900 dark:text-white">
   308→                  {characterProps.name}
   309→                </span>
   310→                <span className="text-sm text-slate-500">
   311→                  • {focusToolType ? focusToolType.charAt(0).toUpperCase() + focusToolType.slice(1) : 'Tool'}
   312→                </span>
   313→              </>
   314→            )}
   315→          </div>
   316→          <div className="flex items-center gap-2">
   317→            <span className="text-xs text-slate-400">ESC per uscire</span>
   318→            <Button
   319→              variant="ghost"
   320→              size="icon"
   321→              onClick={exitFocusMode}
   322→              aria-label="Chiudi"
   323→            >
   324→              <X className="h-5 w-5" />
   325→            </Button>
   326→          </div>
   327→        </header>
   328→
   329→        {/* Main content */}
   330→        <div className="flex h-[calc(100vh-56px)]">
   331→          {/* Left: Chat panel (1/3) */}
   332→          <div className="w-1/3 flex flex-col border-r border-slate-200 dark:border-slate-800">
   333→            {/* Messages */}
   334→            <div className="flex-1 overflow-y-auto p-4 space-y-4">
   335→              {messages.map((message) => (
   336→                <div
   337→                  key={message.id}
   338→                  className={cn(
   339→                    'flex',
   340→                    message.role === 'user' ? 'justify-end' : 'justify-start'
   341→                  )}
   342→                >
   343→                  <div
   344→                    className={cn(
   345→                      'max-w-[85%] rounded-2xl px-4 py-2',
   346→                      message.role === 'user'
   347→                        ? 'bg-accent-themed text-white rounded-br-md'
   348→                        : 'bg-slate-100 dark:bg-slate-800 rounded-bl-md'
   349→                    )}
   350→                  >
   351→                    <p className="text-sm whitespace-pre-wrap">{message.content}</p>
   352→                  </div>
   353→                </div>
   354→              ))}
   355→              {isLoading && (
   356→                <div className="flex justify-start">
   357→                  <div className="bg-slate-100 dark:bg-slate-800 rounded-2xl rounded-bl-md px-4 py-2">
   358→                    <Loader2 className="h-4 w-4 animate-spin" />
   359→                  </div>
   360→                </div>
   361→              )}
   362→              <div ref={messagesEndRef} />
   363→            </div>
   364→
   365→            {/* Input */}
   366→            <div className="p-4 border-t border-slate-200 dark:border-slate-700">
   367→              <div className="flex items-center gap-2">
   368→                <input
   369→                  ref={inputRef}
   370→                  type="text"
   371→                  value={input}
   372→                  onChange={(e) => setInput(e.target.value)}
   373→                  onKeyDown={handleKeyPress}
   374→                  placeholder={`Scrivi a ${characterProps?.name || 'Coach'}...`}
   375→                  className="flex-1 px-4 py-2 bg-slate-100 dark:bg-slate-800 rounded-xl border-0 focus:ring-2 focus:ring-accent-themed outline-none text-sm"
   376→                  disabled={isLoading}
   377→                />
   378→                <Button
   379→                  variant="ghost"
   380→                  size="icon"
   381→                  onClick={() => setIsVoiceActive(!isVoiceActive)}
   382→                  aria-label={isVoiceActive ? 'Disattiva voce' : 'Attiva voce'}
   383→                  className={cn(isVoiceActive && 'bg-red-100 text-red-600')}
   384→                >
   385→                  {isVoiceActive ? <MicOff className="h-4 w-4" /> : <Mic className="h-4 w-4" />}
   386→                </Button>
   387→                <Button
   388→                  size="icon"
   389→                  onClick={handleSend}
   390→                  disabled={!input.trim() || isLoading}
   391→                  className="bg-accent-themed hover:bg-accent-themed/90"
   392→                >
   393→                  <Send className="h-4 w-4" />
   394→                </Button>
   395→              </div>
   396→            </div>
   397→          </div>
   398→
   399→          {/* Right: Tool panel (2/3) */}
   400→          <div className="w-2/3 h-full overflow-hidden bg-slate-50 dark:bg-slate-900">
   401→            {focusTool ? (
   402→              <ToolPanel
   403→                tool={focusTool}
   404→                maestro={characterProps ? {
   405→                  name: characterProps.name,
   406→                  avatar: characterProps.avatar,
   407→                  color: characterProps.color,
   408→                } : null}
   409→                onClose={() => setFocusTool(null)}
   410→                embedded={true}
   411→                sessionId={voiceSessionId}
   412→              />
   413→            ) : (
   414→              <div className="h-full flex items-center justify-center text-slate-400">
   415→                <div className="text-center">
   416→                  <div className="w-16 h-16 mx-auto mb-4 rounded-full bg-slate-200 dark:bg-slate-800 flex items-center justify-center">
   417→                    <Loader2 className="h-6 w-6 animate-spin" />
   418→                  </div>
   419→                  <p className="text-lg font-medium">In attesa dello strumento...</p>
   420→                  <p className="text-sm mt-1">Parla con {characterProps?.name || 'il coach'} per creare il contenuto</p>
   421→                </div>
   422→              </div>
   423→            )}
   424→          </div>
   425→        </div>
   426→      </motion.div>
   427→    </AnimatePresence>
   428→  );
   429→}
