     1→// ============================================================================
     2→// SUMMARY GENERATOR
     3→// Generates and saves conversation summaries when sessions end
     4→// Part of Session Summary & Unified Archive feature
     5→// ============================================================================
     6→
     7→import { prisma } from '@/lib/db';
     8→import { logger } from '@/lib/logger';
     9→import {
    10→  generateConversationSummary,
    11→  extractKeyFacts,
    12→  extractTopics,
    13→  extractLearnings,
    14→} from '@/lib/ai/summarize';
    15→
    16→interface Message {
    17→  role: string;
    18→  content: string;
    19→}
    20→
    21→interface ConversationSummaryResult {
    22→  summary: string;
    23→  keyFacts: {
    24→    decisions: string[];
    25→    preferences: string[];
    26→    learned: string[];
    27→  };
    28→  topics: string[];
    29→  learningsCount: number;
    30→}
    31→
    32→/**
    33→ * End a conversation and generate summary
    34→ * Called on explicit close or inactivity timeout
    35→ */
    36→export async function endConversationWithSummary(
    37→  conversationId: string
    38→): Promise<ConversationSummaryResult | null> {
    39→  try {
    40→    // Fetch conversation with messages
    41→    const conversation = await prisma.conversation.findUnique({
    42→      where: { id: conversationId },
    43→      include: {
    44→        messages: {
    45→          orderBy: { createdAt: 'asc' },
    46→          take: 100, // Limit for summarization
    47→        },
    48→      },
    49→    });
    50→
    51→    if (!conversation) {
    52→      logger.warn('Conversation not found for summary', { conversationId });
    53→      return null;
    54→    }
    55→
    56→    if (!conversation.isActive) {
    57→      logger.debug('Conversation already closed', { conversationId });
    58→      return null;
    59→    }
    60→
    61→    // Convert messages to summary format
    62→    const messages: Message[] = conversation.messages.map((m) => ({
    63→      role: m.role,
    64→      content: m.content,
    65→    }));
    66→
    67→    if (messages.length < 2) {
    68→      // Not enough messages to summarize
    69→      logger.debug('Skipping summary for short conversation', {
    70→        conversationId,
    71→        messageCount: messages.length,
    72→      });
    73→
    74→      // Just mark as inactive
    75→      await prisma.conversation.update({
    76→        where: { id: conversationId },
    77→        data: { isActive: false },
    78→      });
    79→
    80→      return {
    81→        summary: '',
    82→        keyFacts: { decisions: [], preferences: [], learned: [] },
    83→        topics: [],
    84→        learningsCount: 0,
    85→      };
    86→    }
    87→
    88→    // Generate summary and extract data in parallel
    89→    const [summary, keyFacts, topics, learnings] = await Promise.all([
    90→      generateConversationSummary(messages),
    91→      extractKeyFacts(messages),
    92→      extractTopics(messages),
    93→      extractLearnings(messages, conversation.maestroId),
    94→    ]);
    95→
    96→    // Update conversation with summary
    97→    await prisma.conversation.update({
    98→      where: { id: conversationId },
    99→      data: {
   100→        isActive: false,
   101→        summary,
   102→        keyFacts: JSON.stringify(keyFacts),
   103→        topics: JSON.stringify(topics),
   104→      },
   105→    });
   106→
   107→    // Save learnings to the Learning table
   108→    if (learnings.length > 0) {
   109→      const user = await prisma.user.findUnique({
   110→        where: { id: conversation.userId },
   111→        include: { profile: true },
   112→      });
   113→
   114→      for (const learning of learnings) {
   115→        // Check if similar learning already exists
   116→        const existing = await prisma.learning.findFirst({
   117→          where: {
   118→            userId: conversation.userId,
   119→            category: learning.category,
   120→            insight: learning.insight,
   121→          },
   122→        });
   123→
   124→        if (existing) {
   125→          // Update existing - increase confidence and occurrences
   126→          await prisma.learning.update({
   127→            where: { id: existing.id },
   128→            data: {
   129→              confidence: Math.min(1, existing.confidence + learning.confidence * 0.1),
   130→              occurrences: existing.occurrences + 1,
   131→            },
   132→          });
   133→        } else {
   134→          // Create new learning
   135→          await prisma.learning.create({
   136→            data: {
   137→              userId: conversation.userId,
   138→              maestroId: conversation.maestroId,
   139→              subject: user?.profile?.schoolLevel ?? undefined,
   140→              category: learning.category,
   141→              insight: learning.insight,
   142→              confidence: learning.confidence,
   143→            },
   144→          });
   145→        }
   146→      }
   147→    }
   148→
   149→    logger.info('Conversation summary generated', {
   150→      conversationId,
   151→      summaryLength: summary.length,
   152→      topicsCount: topics.length,
   153→      learningsCount: learnings.length,
   154→    });
   155→
   156→    return {
   157→      summary,
   158→      keyFacts,
   159→      topics,
   160→      learningsCount: learnings.length,
   161→    };
   162→  } catch (error) {
   163→    logger.error('Failed to generate conversation summary', {
   164→      conversationId,
   165→      error: String(error),
   166→    });
   167→    throw error;
   168→  }
   169→}
   170→
   171→/**
   172→ * Get the last summary for a character from a user
   173→ * Used for contextual greetings
   174→ */
   175→export async function getLastConversationSummary(
   176→  userId: string,
   177→  characterId: string
   178→): Promise<{
   179→  summary: string;
   180→  topics: string[];
   181→  lastMessageAt: Date | null;
   182→} | null> {
   183→  const conversation = await prisma.conversation.findFirst({
   184→    where: {
   185→      userId,
   186→      maestroId: characterId,
   187→      isActive: false,
   188→      summary: { not: null },
   189→    },
   190→    orderBy: { updatedAt: 'desc' },
   191→  });
   192→
   193→  if (!conversation || !conversation.summary) {
   194→    return null;
   195→  }
   196→
   197→  return {
   198→    summary: conversation.summary,
   199→    topics: JSON.parse(conversation.topics) as string[],
   200→    lastMessageAt: conversation.lastMessageAt,
   201→  };
   202→}
   203→
   204→/**
   205→ * Get recent summaries for a user (for dashboard/overview)
   206→ */
   207→export async function getRecentSummaries(
   208→  userId: string,
   209→  limit: number = 5
   210→): Promise<
   211→  Array<{
   212→    id: string;
   213→    maestroId: string;
