// ============================================================================
// LLM SUMMARIZATION & LEARNING EXTRACTION
// Used to compress conversations and extract user insights
// ============================================================================

import { chatCompletion, getActiveProvider } from './providers';
import { logger } from '@/lib/logger';

interface Message {
  role: string;
  content: string;
}

interface KeyFacts {
  decisions: string[];
  preferences: string[];
  learned: string[];
}

interface Learning {
  category: 'preference' | 'strength' | 'weakness' | 'interest' | 'style';
  insight: string;
  confidence: number;
}

/**
 * Generate a summary of conversation messages
 * Used when conversation gets too long to maintain context
 */
export async function generateConversationSummary(
  messages: Message[]
): Promise<string> {
  const provider = getActiveProvider();
  if (!provider) {
    throw new Error('No AI provider available for summarization');
  }

  const systemPrompt = `Sei un assistente che riassume conversazioni educative.
Crea un riassunto conciso che catturi:
- Argomenti principali discussi
- Domande chiave dello studente
- Concetti spiegati
- Eventuali difficoltà emerse

Rispondi in italiano, max 200 parole.
Usa un linguaggio chiaro e diretto.`;

  const userPrompt = `Riassumi questa conversazione:

${messages.map((m) => `${m.role === 'user' ? 'STUDENTE' : 'MAESTRO'}: ${m.content}`).join('\n\n')}`;

  const result = await chatCompletion(
    [{ role: 'user', content: userPrompt }],
    systemPrompt
  );

  return result.content;
}

/**
 * Extract key facts from conversation
 * Identifies decisions, preferences, and what was learned
 */
export async function extractKeyFacts(messages: Message[]): Promise<KeyFacts> {
  const provider = getActiveProvider();
  if (!provider) {
    return { decisions: [], preferences: [], learned: [] };
  }

  const systemPrompt = `Estrai informazioni chiave dalla conversazione educativa in formato JSON.

Rispondi SOLO con JSON valido in questo formato:
{
  "decisions": ["decisioni prese dallo studente - es. 'vuole approfondire le frazioni'"],
  "preferences": ["preferenze di apprendimento espresse - es. 'preferisce esempi visivi'"],
  "learned": ["concetti che lo studente ha capito - es. 'comprende le operazioni base'"]
}

Se non ci sono informazioni per una categoria, usa un array vuoto.
Max 3 elementi per categoria.`;

  const userPrompt = messages
    .map((m) => `${m.role === 'user' ? 'STUDENTE' : 'MAESTRO'}: ${m.content}`)
    .join('\n\n');

  try {
    const result = await chatCompletion(
      [{ role: 'user', content: userPrompt }],
      systemPrompt
    );

    // Parse JSON from response
    const jsonMatch = result.content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      return JSON.parse(jsonMatch[0]);
    }
  } catch (error) {
    logger.error('Failed to extract key facts', { error: String(error) });
  }

  return { decisions: [], preferences: [], learned: [] };
}

/**
 * Extract conversation topics
 * Returns list of main subjects discussed
 */
export async function extractTopics(messages: Message[]): Promise<string[]> {
  const provider = getActiveProvider();
  if (!provider) {
    return [];
  }

  const systemPrompt = `Identifica gli argomenti principali discussi nella conversazione educativa.

Rispondi SOLO con un array JSON di stringhe, max 5 argomenti.
Esempio: ["Matematica - Frazioni", "Geometria - Perimetro", "Esercizi pratici"]

Usa termini brevi e chiari.`;

  const userPrompt = messages
    .map((m) => `${m.role === 'user' ? 'STUDENTE' : 'MAESTRO'}: ${m.content}`)
    .join('\n\n');

  try {
    const result = await chatCompletion(
      [{ role: 'user', content: userPrompt }],
      systemPrompt
    );

    // Parse JSON array from response
    const arrayMatch = result.content.match(/\[[\s\S]*\]/);
    if (arrayMatch) {
      return JSON.parse(arrayMatch[0]);
    }
  } catch (error) {
    logger.error('Failed to extract topics', { error: String(error) });
  }

  return [];
}

/**
 * Extract learnings about the student
 * These are cross-session insights that help personalize future interactions
 */
export async function extractLearnings(
  messages: Message[],
  _maestroId: string,
  _subject?: string
): Promise<Learning[]> {
  const provider = getActiveProvider();
  if (!provider) {
    return [];
  }

  const systemPrompt = `Analizza la conversazione e identifica caratteristiche dello studente.

Categorie disponibili:
- preference: preferenze di apprendimento (es. "Preferisce esempi pratici")
- strength: punti di forza (es. "Buona memoria visiva")
- weakness: difficoltà (es. "Difficoltà con le frazioni")
- interest: interessi espressi (es. "Interessato alla programmazione")
- style: stile di apprendimento (es. "Apprende meglio con esercizi guidati")

Rispondi SOLO con un array JSON:
[
  {"category": "preference", "insight": "descrizione breve", "confidence": 0.7},
  {"category": "weakness", "insight": "descrizione breve", "confidence": 0.6}
]

Regole:
- Max 3 insights
- Solo caratteristiche evidenti dalla conversazione
- Confidence da 0.3 (debole) a 0.9 (molto evidente)
- Se non ci sono insights chiari, rispondi con []`;

  const userPrompt = messages
    .map((m) => `${m.role === 'user' ? 'STUDENTE' : 'MAESTRO'}: ${m.content}`)
    .join('\n\n');

  try {
    const result = await chatCompletion(
      [{ role: 'user', content: userPrompt }],
      systemPrompt
    );

    // Parse JSON array from response
    const arrayMatch = result.content.match(/\[[\s\S]*\]/);
    if (arrayMatch) {
      const learnings = JSON.parse(arrayMatch[0]) as Learning[];
      // Validate and filter
      return learnings
        .filter(
          (l) =>
            ['preference', 'strength', 'weakness', 'interest', 'style'].includes(l.category) &&
            l.insight &&
            l.confidence >= 0.3 &&
            l.confidence <= 1
        )
        .slice(0, 3);
    }
  } catch (error) {
    logger.error('Failed to extract learnings', { error: String(error) });
  }

  return [];
}

/**
 * Generate a title for a conversation from its first messages
 */
export async function generateConversationTitle(
  messages: Message[]
): Promise<string> {
  if (messages.length === 0) {
    return 'Nuova conversazione';
  }

  // If there's a user message, use it directly (truncated)
  const firstUserMsg = messages.find((m) => m.role === 'user');
  if (firstUserMsg) {
    const title = firstUserMsg.content.slice(0, 50);
    return title.length < firstUserMsg.content.length ? `${title}...` : title;
  }

  return 'Nuova conversazione';
}

// ============================================================================
// TOOL TYPES - Unified across voice and chat
// Related: ADR 0009 - Tool Execution Architecture
// ============================================================================

/**
 * All supported tool types in ConvergioEdu
 */
export type ToolType =
  | 'mindmap'      // Mappa mentale interattiva (MarkMap)
  | 'quiz'         // Quiz con domande a risposta multipla
  | 'flashcard'    // Set di flashcard per ripasso (FSRS)
  | 'demo'         // Simulazione HTML/JS interattiva
  | 'search'       // Ricerca web/YouTube
  | 'diagram'      // Diagramma (Mermaid)
  | 'timeline'     // Linea temporale
  | 'summary'      // Riassunto strutturato
  | 'formula'      // Formula matematica (KaTeX)
  | 'chart'        // Grafico (Chart.js)
  | 'webcam'       // Foto da webcam
  | 'pdf'          // PDF caricato
  | 'homework';    // Compiti con metodo maieutico

/**
 * OpenAI function definitions for chat API
 * These are passed to the `tools` parameter in chat completions
 */
export const CHAT_TOOL_DEFINITIONS = [
  {
    type: 'function' as const,
    function: {
      name: 'create_mindmap',
      description: `Crea una mappa mentale interattiva ben strutturata su un argomento. Usa questo strumento quando lo studente chiede di visualizzare concetti, creare schemi, o organizzare informazioni.

IMPORTANTE - Struttura della mappa:
- Il "title" è il nodo centrale/principale della mappa
- I nodi senza parentId sono i RAMI PRINCIPALI che partono dal centro
- Ogni ramo principale deve avere 2-4 sotto-nodi (con parentId = id del ramo)
- Crea almeno 3-5 rami principali per una mappa utile
- Usa 2-3 livelli di profondità (rami → sotto-rami → dettagli)

Esempio di struttura per "Fotosintesi":
- title: "La Fotosintesi"
- Rami principali (parentId omesso): "Fase Luminosa", "Fase Oscura", "Fattori Limitanti", "Importanza"
- Sotto-rami di "Fase Luminosa": "Clorofilla", "Acqua", "ATP e NADPH"`,
      parameters: {
        type: 'object',
        properties: {
          title: {
            type: 'string',
            description: 'Titolo/argomento principale che appare al CENTRO della mappa mentale',
          },
          nodes: {
            type: 'array',
            description: 'Nodi della mappa organizzati gerarchicamente. I nodi senza parentId sono i rami principali dal centro. I sotto-nodi hanno parentId = id del loro nodo padre.',
            items: {
              type: 'object',
              properties: {
                id: { type: 'string', description: 'ID univoco del nodo (es: "1", "2", "2a", "2b")' },
                label: { type: 'string', description: 'Testo breve del nodo (max 5-7 parole)' },
                parentId: { type: 'string', description: 'ID del nodo padre. OMETTI per i rami principali (che partono dal centro). INCLUDI per i sotto-nodi.' },
              },
              required: ['id', 'label'],
            },
          },
        },
        required: ['title', 'nodes'],
      },
    },
  },
  {
    type: 'function' as const,
    function: {
      name: 'create_quiz',
      description: 'Crea un quiz interattivo con domande a risposta multipla. Usa questo strumento quando lo studente vuole testare la sua comprensione o ripassare.',
      parameters: {
        type: 'object',
        properties: {
          topic: {
            type: 'string',
            description: 'Argomento del quiz',
          },
          questions: {
            type: 'array',
            description: 'Domande del quiz',
            items: {
              type: 'object',
              properties: {
                question: { type: 'string', description: 'Testo della domanda' },
                options: {
                  type: 'array',
                  items: { type: 'string' },
                  description: 'Opzioni di risposta (4 opzioni)',
                },
                correctIndex: {
                  type: 'number',
                  description: 'Indice della risposta corretta (0-3)',
                },
                explanation: {
                  type: 'string',

