  sessionId?: string;
  userId?: string;
  maestroId?: string;
  conversationId?: string;
}

/**
 * Result of tool execution
 */
export interface ToolExecutionResult {
  success: boolean;
  toolId: string;
  toolType: ToolType;
  data?: unknown;
  error?: string;
}

