'use client';

/**
 * StudentSummaryEditor - Main editor for student-written summaries
 * Part of Issue #70: Collaborative summary writing with maieutic method
 */

import { useState, useCallback, useEffect, forwardRef, useImperativeHandle, useMemo } from 'react';
import { motion } from 'framer-motion';
import { FileText, Save, Loader2, CheckCircle2, Clock, Layout } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { cn } from '@/lib/utils';
import { GuidedSection, SectionOverview } from './guided-section';
import { createEmptyStudentSummary, type StudentSummaryData, type InlineComment } from '@/types/tools';
import { calculateTotalWordCount } from '@/lib/hooks/use-student-summary-sync';

export interface StudentSummaryEditorProps {
  initialData?: StudentSummaryData;
  topic?: string;
  maestroId?: string;
  sessionId?: string;
  onSave?: (data: StudentSummaryData) => Promise<void>;
  onTitleChange?: (title: string) => void;
  onContentChange?: (sectionId: string, content: string) => void;
  readOnly?: boolean;
  className?: string;
}

export interface StudentSummaryEditorHandle {
  getSummaryData: () => StudentSummaryData;
  setTitle: (title: string) => void;
  setSectionContent: (sectionId: string, content: string) => void;
  addComment: (sectionId: string, comment: Omit<InlineComment, 'id' | 'createdAt'>) => void;
  removeComment: (sectionId: string, commentId: string) => void;
  resolveComment: (sectionId: string, commentId: string) => void;
  save: () => Promise<void>;
  focusSection: (sectionId: string) => void;
}

export const StudentSummaryEditor = forwardRef<StudentSummaryEditorHandle, StudentSummaryEditorProps>(
  function StudentSummaryEditor({ initialData, topic = '', maestroId, sessionId, onSave, onTitleChange, onContentChange, readOnly = false, className }, ref) {
    const [summaryData, setSummaryData] = useState<StudentSummaryData>(() => initialData || createEmptyStudentSummary(topic, maestroId, sessionId));
    const [activeSectionId, setActiveSectionId] = useState('intro');
    const [isSaving, setIsSaving] = useState(false);
    const [lastSaved, setLastSaved] = useState<Date | null>(null);
    const [showSidebar, setShowSidebar] = useState(true);

    const totalWordCount = useMemo(() => calculateTotalWordCount(summaryData.sections), [summaryData.sections]);

    useEffect(() => {
      setSummaryData((prev) => ({ ...prev, wordCount: totalWordCount, lastModifiedAt: new Date() }));
    }, [totalWordCount]);

    const handleTitleChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
      const newTitle = e.target.value;
      setSummaryData((prev) => ({ ...prev, title: newTitle, lastModifiedAt: new Date() }));
      onTitleChange?.(newTitle);
    }, [onTitleChange]);

    const handleSectionContentChange = useCallback((sectionId: string, content: string) => {
      setSummaryData((prev) => ({
        ...prev,
        sections: prev.sections.map((s) => s.id === sectionId ? { ...s, content } : s),
        lastModifiedAt: new Date(),
      }));
      onContentChange?.(sectionId, content);
    }, [onContentChange]);

    const handleResolveComment = useCallback((sectionId: string, commentId: string) => {
      setSummaryData((prev) => ({
        ...prev,
        sections: prev.sections.map((s) => s.id === sectionId
          ? { ...s, comments: s.comments.map((c) => c.id === commentId ? { ...c, resolved: true } : c) }
          : s
        ),
      }));
    }, []);

    const handleSave = useCallback(async () => {
      if (!onSave) return;
      setIsSaving(true);
      try {
        await onSave(summaryData);
        setLastSaved(new Date());
      } finally {
        setIsSaving(false);
      }
    }, [onSave, summaryData]);

    useImperativeHandle(ref, () => ({
      getSummaryData: () => summaryData,
      setTitle: (title) => setSummaryData((prev) => ({ ...prev, title, lastModifiedAt: new Date() })),
      setSectionContent: handleSectionContentChange,
      addComment: (sectionId, comment) => {
